parameters.query:
={{
  JSON.stringify(
    (() => {
      try {
        let val = String($fromAI('input', '', 'string') || "").trim();

        // Kalau AI kirim kalimat penuh, coba ekstrak lokasi dari kata setelah "di"
        let lokasiStr = "";
        let kategoriStr = "semua";

        // Cek apakah format pipe sudah benar
        if (val.includes('|')) {
          let parts = val.split('|');
          kategoriStr = parts[0].trim();
          lokasiStr = parts[1].trim();
        } else {
          // Fallback: ekstrak dari kalimat
          let diMatch = val.match(/\bdi\s+(.+)/i);
          if (diMatch) lokasiStr = diMatch[1].replace(/[?.!]/g, '').trim();

          // Deteksi jenis kejadian
          if (/kebakaran/i.test(val)) kategoriStr = "Kebakaran";
          else if (/kecelakaan/i.test(val)) kategoriStr = "Kecelakaan";
          else if (/kemacetan|macet/i.test(val)) kategoriStr = "Kemacetan";
          else if (/banjir/i.test(val)) kategoriStr = "Banjir";
        }

        if (!lokasiStr) return { "status": "BLOCK_EMPTY_SEARCH" };

        let queryAnd = [];
        queryAnd.push({ "status": "processed" });

        if (kategoriStr.toLowerCase() !== "semua") {
          queryAnd.push({ "incident_type": { "$regex": kategoriStr, "$options": "i" } });
        }

        let lokasiWords = lokasiStr.replace(/[^a-zA-Z0-9\s]/g, ' ').trim().split(/\s+/).filter(w => w.length > 2);
        if (lokasiWords.length === 0) return { "status": "BLOCK_EMPTY_SEARCH" };

        lokasiWords.forEach(w => {
          queryAnd.push({
            "$or": [
              { "street_name": { "$regex": w, "$options": "i" } },
              { "text": { "$regex": w, "$options": "i" } }
            ]
          });
        });

        return { "$and": queryAnd };
      } catch(e) {
        return { "status": "BLOCK_EMPTY_SEARCH" };
      }
    })()
  )
}}
